   311→function sliderThumbCenterPercent(
   312→  valuePct: number,
   313→  trackPx: number,
   314→  thumbPx: number,
   315→): string {
   316→  const clamped = Math.max(0, Math.min(100, valuePct));
   317→  const min = thumbPx * 0.5;
   318→  const max = Math.max(min, trackPx - thumbPx * 0.5);
   319→  const center = min + ((max - min) * clamped) / 100;
   320→  return `${(center / trackPx) * 100}%`;
   321→}
   322→
   323→function verticalThumbCenterPx(
   324→  valuePct: number,
   325→  trackTopPx: number,
   326→  trackHeightPx: number,
   327→  thumbPx: number,
   328→): string {
   329→  const clamped = Math.max(0, Math.min(100, valuePct));
   330→  const min = trackTopPx + thumbPx * 0.5;
   331→  const max = Math.max(min, trackTopPx + trackHeightPx - thumbPx * 0.5);
   332→  const center = min + ((max - min) * clamped) / 100;
   333→  return `${center}px`;
   334→}
