   904→function compositeSrcColorAdditive(
   905→  dstCtx: CanvasRenderingContext2D,
   906→  pxW: number,
   907→  pxH: number,
   908→  dpr: number,
   909→  cssW: number,
   910→  cssH: number,
   911→  drawSource: (ctx: CanvasRenderingContext2D) => void,
   912→) {
   913→  if (
   914→    additiveSrcColorScratchCanvas.width !== pxW ||
   915→    additiveSrcColorScratchCanvas.height !== pxH
   916→  ) {
   917→    additiveSrcColorScratchCanvas.width = pxW;
   918→    additiveSrcColorScratchCanvas.height = pxH;
   919→  }
   920→
   921→  const srcCtx = additiveSrcColorScratchCanvas.getContext("2d");
   922→  if (!srcCtx) return;
   923→  srcCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
   924→  srcCtx.clearRect(0, 0, cssW, cssH);
   925→  srcCtx.imageSmoothingEnabled = true;
   926→  drawSource(srcCtx);
   927→
   928→  const srcImage = srcCtx.getImageData(0, 0, pxW, pxH);
   929→  const dstImage = dstCtx.getImageData(0, 0, pxW, pxH);
   930→  const src = srcImage.data;
   931→  const dst = dstImage.data;
   932→
   933→  // Warcraft III Additive layer mode maps to GL blendFunc(SRC_COLOR, ONE).
   934→  for (let i = 0; i < dst.length; i += 4) {
   935→    const srcR = src[i] / 255;
   936→    const srcG = src[i + 1] / 255;
   937→    const srcB = src[i + 2] / 255;
   938→    const srcA = src[i + 3] / 255;
   939→    dst[i] = Math.min(255, dst[i] + Math.round(srcR * srcR * 255));
   940→    dst[i + 1] = Math.min(255, dst[i + 1] + Math.round(srcG * srcG * 255));
   941→    dst[i + 2] = Math.min(255, dst[i + 2] + Math.round(srcB * srcB * 255));
   942→    dst[i + 3] = Math.min(255, dst[i + 3] + Math.round(srcA * srcA * 255));
   943→  }
   944→
   945→  dstCtx.putImageData(dstImage, 0, 0);
   946→}
