  1032→    Math.round(a[0] + (b[0] - a[0]) * clamped),
  1033→    Math.round(a[1] + (b[1] - a[1]) * clamped),
  1034→    Math.round(a[2] + (b[2] - a[2]) * clamped),
  1035→  ];
  1036→}
