  1057→function interpolateKeyframes(
  1058→  ms: number,
  1059→  keyframes: ReadonlyArray<readonly [number, number]>,
  1060→): number {
  1061→  if (keyframes.length === 0) return 0;
  1062→  if (ms <= keyframes[0][0]) return keyframes[0][1];
  1063→  for (let i = 1; i < keyframes.length; i++) {
  1064→    const [frameMs, frameVal] = keyframes[i];
  1065→    const [prevMs, prevVal] = keyframes[i - 1];
  1066→    if (ms <= frameMs) {
  1067→      const t = (ms - prevMs) / Math.max(0.0001, frameMs - prevMs);
  1068→      return prevVal + (frameVal - prevVal) * t;
  1069→    }
  1070→  }
  1071→  return keyframes[keyframes.length - 1][1];
  1072→}
